import { writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";

const CELL_COUNT = 1024;
const outputUrl = new URL("../examples/large_buffer_chain_1024.v", import.meta.url);
const lines = [
  "// Generated by tools/generate-large-example.mjs. Do not edit manually.",
  "// Stage 4 smoke example: 1024-cell deep buffer chain.",
  "module large_buffer_chain_1024 (clk, data_in, data_out);",
  "input clk;",
  "input data_in;",
  "output data_out;",
  `wire ${Array.from({ length: CELL_COUNT - 1 }, (_, index) => `n${index}`).join(", ")};`,
  ""
];

for (let index = 0; index < CELL_COUNT; index += 1) {
  const input = index === 0 ? "data_in" : `n${index - 1}`;
  const output = index === CELL_COUNT - 1 ? "data_out" : `n${index}`;
  lines.push(`BUF_X1 u_buf_${index} (.A(${input}), .Z(${output}));`);
}

lines.push("", "endmodule", "");
await writeFile(outputUrl, lines.join("\n"), "utf8");
console.log(`Generated ${fileURLToPath(outputUrl)} with ${CELL_COUNT} cells`);
